#include <stdio.h>
#include <stdlib.h>

int max(int a, int b) { return (a > b) ? a : b; }

int main() {
    int N;
    scanf("%d", &N);
    int* A = (int*) malloc(N * sizeof(int));
    int* B = (int*) malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        scanf("%d", &A[i]);
    }
    for (int i = 0; i < N; i++) {
        scanf("%d", &B[i]);
    }
    int** C = (int**) malloc(N * sizeof(int*));
    for (int i = 0; i < N; i++) {
        C[i] = (int*) malloc(N * sizeof(int));
    }
    for (int i = 0; i < N; i++) {
        for (int j = 0; j < N; j++) {
            C[i][j] = A[i] * B[j];
        }
    }
    for (int K = 1; K <= N; K++) {
        int maxSum = 0;
        for (int i = 0; i <= N - K; i++) {
            for (int j = 0; j <= N - K; j++) {
                int sum = 0;
                for (int x = 0; x < K; x++) {
                    for (int y = 0; y < K; y++) {
                        sum += C[i + x][j + y];
                    }
                }
                maxSum = max(maxSum, sum);
            }
        }
        printf("%d ", maxSum);
    }
    return 0;
}

