import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();
        int[] A = new int[N];
        int[] B = new int[N];
        for (int i = 0; i < N; i++) {
            A[i] = sc.nextInt();
        }
        for (int i = 0; i < N; i++) {
            B[i] = sc.nextInt();
        }
        int[][] C = new int[N][N];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                C[i][j] = A[i] * B[j];
            }
        }
        for (int K = 1; K <= N; K++) {
            int maxSum = 0;
            for (int i = 0; i <= N - K; i++) {
                for (int j = 0; j <= N - K; j++) {
                    int sum = 0;
                    for (int x = 0; x < K; x++) {
                        for (int y = 0; y < K; y++) {
                            sum += C[i + x][j + y];
                        }
                    }
                    maxSum = Math.max(maxSum, sum);
                }
            }
            System.out.print(maxSum + " ");
        }
    }
}

